 1	import * as React from 'react';
 2	
 3	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes';
 4	import NodeCheckerAlert from '@kubevirt-utils/components/NodeSelectorModal/components/NodeCheckerAlert';
 5	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Stack, StackItem } from '@patternfly/react-core';
 7	
 8	import { AffinityRowData, AffinityType } from '../../utils/types';
 9	import AddAffinityRuleButton from '../AddAffinityRuleButton';
10	import AffinityDescriptionText from '../AffinityDescriptionText';
11	
12	import AffinityRow from './components/AffinityRow';
13	import useAffinityColumns from './hooks/useAffinityColumns';
14	
15	type AffinityListProps = {
16	  affinities: AffinityRowData[];
17	  nodesLoaded: boolean;
18	  onAffinityClickAdd: () => void;
19	  onDelete: (affinity: AffinityRowData) => void;
20	  onEdit: (affinity: AffinityRowData) => void;
21	  prefferedQualifiedNodes: IoK8sApiCoreV1Node[];
22	  qualifiedNodes: IoK8sApiCoreV1Node[];
23	};
24	
25	const AffinityList: React.FC<AffinityListProps> = ({
26	  affinities,
27	  nodesLoaded,
28	  onAffinityClickAdd,
29	  onDelete,
30	  onEdit,
31	  prefferedQualifiedNodes,
32	  qualifiedNodes,
33	}) => {
34	  const columns = useAffinityColumns();
35	  return (
36	    <Stack hasGutter>
37	      <StackItem>
38	        <AffinityDescriptionText />
39	      </StackItem>
40	      <StackItem>
41	        <VirtualizedTable<AffinityRowData>
42	          columns={columns}
43	          data={affinities || []}
44	          loaded
45	          loadError={false}
46	          Row={AffinityRow}
47	          rowData={{ onDelete, onEdit }}
48	          unfilteredData={affinities || []}
49	        />
50	      </StackItem>
51	      <StackItem>
52	        <AddAffinityRuleButton isLinkButton onAffinityClickAdd={onAffinityClickAdd} />
53	      </StackItem>
54	      <StackItem>
55	        {affinities?.some((affinity) => affinity?.type === AffinityType.node) && nodesLoaded && (
56	          <NodeCheckerAlert
57	            nodesLoaded={nodesLoaded}
58	            prefferedQualifiedNodes={prefferedQualifiedNodes}
59	            qualifiedNodes={qualifiedNodes}
60	          />
61	        )}
62	      </StackItem>
63	    </Stack>
64	  );
65	};
66	export default AffinityList;

